+namespace sv_d974276f103d4629aa0f42ad5c50ac0e.Services;
+
+public class NotificationItem
+{
+    public int Id { get; set; }
+    public string Message { get; set; } = string.Empty;
+    public DateTime Timestamp { get; set; }
+}
+
+public class NotificationService
+{
+    private int _nextId = 4;
+
+    private readonly List<NotificationItem> _notifications =
+    [
+        new() { Id = 1, Message = "Welcome to the app!", Timestamp = DateTime.Now.AddMinutes(-10) },
+        new() { Id = 2, Message = "Your profile was updated.", Timestamp = DateTime.Now.AddMinutes(-5) },
+        new() { Id = 3, Message = "New feature available: dark mode.", Timestamp = DateTime.Now.AddMinutes(-2) },
+    ];
+
+    public Task<List<NotificationItem>> GetNotificationsAsync()
+    {
+        lock (_notifications)
+        {
+            return Task.FromResult(_notifications.ToList());
+        }
+    }
+
+    public Task<List<NotificationItem>> GetNotificationsSinceAsync(int lastId)
+    {
+        lock (_notifications)
+        {
+            var newer = _notifications.Where(n => n.Id > lastId).ToList();
+
+            // Simulate a new notification arriving roughly every other poll
+            if (Random.Shared.Next(2) == 0)
+            {
+                var item = new NotificationItem
+                {
+                    Id = _nextId++,
+                    Message = $"New activity detected at {DateTime.Now:T}",
+                    Timestamp = DateTime.Now,
+                };
+                _notifications.Add(item);
+                newer.Add(item);
+            }
+
+            return Task.FromResult(newer);
+        }
+    }
+}
+

